from datetime import datetime, timezone
import time
import logging

log = logging.getLogger(__name__)


class Scheduler:
    def __init__(self):
        self.jobs = []
        self.last_run = {}

    def add_daily(self, name: str, hour_utc: int, func):
        """Schedule daily job at specified UTC hour."""
        self.jobs.append({'name': name, 'hour': hour_utc, 'func': func})

    def run(self):
        while True:
            now = datetime.now(timezone.utc)
            for job in self.jobs:
                if now.hour == job['hour'] and now.minute < 1:
                    run_key = f"{job['name']}:{now.date().isoformat()}"
                    if run_key not in self.last_run:
                        log.info('Running job: %s', job['name'])
                        job['func']()
                        self.last_run[run_key] = True
            time.sleep(30)
